import{_ as r,o,c as a,ag as l}from"./chunks/framework.D2Ob5GRY.js";const m=JSON.parse('{"title":"性能优化建议","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/performance.md","filePath":"troubleshooting/performance.md"}'),i={name:"troubleshooting/performance.md"};function t(n,e,s,h,d,c){return o(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="性能优化建议" tabindex="-1">性能优化建议 <a class="header-anchor" href="#性能优化建议" aria-label="Permalink to &quot;性能优化建议&quot;">​</a></h1><blockquote><p>推荐 LLM Provider、并发与服务器配置、响应慢的排查路径。</p></blockquote><h2 id="推荐使用哪个-llm-provider-延迟和价格对比" tabindex="-1">推荐使用哪个 LLM Provider（延迟和价格对比） <a class="header-anchor" href="#推荐使用哪个-llm-provider-延迟和价格对比" aria-label="Permalink to &quot;推荐使用哪个 LLM Provider（延迟和价格对比）&quot;">​</a></h2><ul><li><strong>DeepSeek</strong>：国内直连，延迟较低，价格友好，适合多数场景。</li><li><strong>通义/ DashScope</strong>：国内直连，模型选择多。</li><li><strong>OpenAI / Gemini</strong>：需代理，延迟与稳定性受网络影响；适合对模型能力要求高的场景。</li><li>具体价格与延迟以各厂商当前公布为准，可结合 <a href="/docs/reference/llm-reference.html">LLM Provider 参数参考</a> 选择。</li></ul><h2 id="并发用户数与服务器配置的关系" tabindex="-1">并发用户数与服务器配置的关系 <a class="header-anchor" href="#并发用户数与服务器配置的关系" aria-label="Permalink to &quot;并发用户数与服务器配置的关系&quot;">​</a></h2><ul><li>并发越高，对 CPU、内存与 LLM 调用 QPS 要求越高；建议根据实际并发数压测后调整服务器配置与 Provider 限流策略。</li><li>数据库连接池、任务队列 worker 数等可参考项目部署文档调优。</li></ul><h2 id="响应慢的排查路径" tabindex="-1">响应慢的排查路径 <a class="header-anchor" href="#响应慢的排查路径" aria-label="Permalink to &quot;响应慢的排查路径&quot;">​</a></h2><ol><li>确认 LLM 请求是否耗时（查看网络延迟与模型响应时间）。</li><li>检查数据库是否有慢查询（日志或监控）。</li><li>检查任务队列是否积压；必要时增加 worker 或扩容。</li><li>若为代理访问海外 API，可尝试更换代理或改用国内 Provider。</li></ol><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/troubleshooting/backup-and-migration.html">数据备份与迁移</a></li><li><a href="/docs/troubleshooting/common-errors.html">常见错误与解决方法</a></li></ul>',10)])])}const p=r(i,[["render",t]]);export{m as __pageData,p as default};
